import React from 'react'
import ComponentBox from '../../../../shared/tags/ComponentBox'
import styled from '@emotion/styled'
import { Provider } from '@dnb/eufemia/src/shared'
import { Flex, InputMasked } from '@dnb/eufemia/src'

export const InputMaskedExampleNumberLocale = () => (
  <Wrapper>
    <ComponentBox data-visual-test="input-masked-number">
      <Flex.Vertical>
        <InputMasked
          label="Number"
          asNumber
          maskOptions={{ allowNegative: false }}
          value="1234.50"
          onChange={({ numberValue }) => {
            console.log(numberValue)
          }}
        />
        <InputMasked
          label="Number (decimal limit)"
          asNumber
          numberMask={{ decimalLimit: 2 }}
          value="1234.016"
          onChange={({ numberValue }) => {
            console.log(numberValue)
          }}
        />
        <InputMasked
          label="Percentage"
          asPercent
          numberMask={{ decimalLimit: 1 }}
          value="1234.016"
          onChange={({ numberValue }) => {
            console.log(numberValue)
          }}
        />
      </Flex.Vertical>
    </ComponentBox>
  </Wrapper>
)

export const InputMaskedExampleCurrencyLocale = () => (
  <Wrapper>
    <ComponentBox data-visual-test="input-masked-currency">
      <Flex.Vertical>
        <InputMasked
          label="Currency"
          asCurrency="EUR"
          value="1234.50"
          onChange={({ numberValue }) => {
            console.log(numberValue)
          }}
        />
        <Provider
          locale="en-GB"
          InputMasked={{
            currencyMask: {
              decimalLimit: 3,
            },
          }}
        >
          <InputMasked
            label="Currency"
            asCurrency="USD"
            value="1234.567"
            onChange={({ numberValue }) => {
              console.log(numberValue)
            }}
          />
        </Provider>
      </Flex.Vertical>
    </ComponentBox>
  </Wrapper>
)

export const InputMaskedExampleCurrencyMask = () => (
  <Wrapper>
    <ComponentBox data-visual-test="input-masked-currency_mask">
      <Flex.Vertical>
        <InputMasked
          label="Left aligned (default)"
          showMask
          currencyMask="kr"
          onChange={({ numberValue }) => {
            console.log(numberValue)
          }}
        />
        <InputMasked
          label="Right aligned"
          showMask
          currencyMask={{ currency: 'NOK' }}
          align="right"
          onChange={({ numberValue }) => {
            console.log(numberValue)
          }}
        />
      </Flex.Vertical>
    </ComponentBox>
  </Wrapper>
)

export const InputMaskedExampleCustomNumberMask = () => (
  <Wrapper>
    <ComponentBox>
      <InputMasked
        label="Masked amount"
        showMask
        numberMask={{
          suffix: ' kr',
          allowDecimal: true,
        }}
        onChange={({ numberValue }) => {
          console.log(numberValue)
        }}
      />
    </ComponentBox>
  </Wrapper>
)

